  ('aboriginal-6f0ba476-moex-00564', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-111-f6c431ec', 'sub-aboriginal-6f0ba476-04', NULL, 'single_choice', '假設投票者對公共財需求與其所得呈現正相關，所得分配為一右偏分配。如果投票者的偏好均為 單峰，根據中位數投票者理論所決定的公共財數量，下列敘述何者正確？', '["經由民主投票所決定，必定符合柏瑞圖最適提供水準", "雖經由民主投票所決定，但未必符合柏瑞圖最適提供水準", "僅由中位數投票者偏好來決定，既不民主亦不符合柏瑞圖最適提供水準", "僅由中位數投票者偏好來決定，雖不民主但卻符合柏瑞圖最適提供水準"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:57+00:00", "source_pdf_sha1": "76077efefc27", "answer_pdf_sha1": "92dbc480fa7e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "506", "s": "1201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "財政學", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00565', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-111-f6c431ec', 'sub-aboriginal-6f0ba476-04', NULL, 'single_choice', '假設社會上只有A、B二人，其效用函數各別以U 與U 表示。如果社會福利函數為羅斯（J.Rawls） A B 提出的極大化極小函數型態，則下列敘述何者正確？', '["社會福利函數可表示為：U ＋U A B", "社會福利函數可表示為：Max｛U ，U ｝ A B", "U 與U 的效用在社會福利函數中為完全替代 A B", "U 與U 的效用在社會福利函數中為完全互補 A B"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:57+00:00", "source_pdf_sha1": "76077efefc27", "answer_pdf_sha1": "92dbc480fa7e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "506", "s": "1201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "財政學", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
